'use client';

import { motion, useReducedMotion } from 'framer-motion';

const STACKS = [
  { label: 'WordPress', color: '#21759b' },
  { label: 'Shopify', color: '#95bf47' },
  { label: 'Next.js', color: '#111827' },
  { label: 'React', color: '#149eca' },
  { label: 'GSAP', color: '#6b9e2e' },
  { label: 'EC-CUBE', color: '#c30d23' },
] as const;

const CYCLE = 8;

function InputBox({
  label,
  color,
  row,
  delay,
  paused,
}: {
  label: string;
  color: string;
  row: number;
  delay: number;
  paused: boolean;
}) {
  const y = row * 52;

  if (paused) {
    return (
      <div
        className="absolute left-4 flex h-11 w-[7.5rem] items-center justify-center rounded-md border-2 border-white/30 text-[10px] font-bold text-white shadow-md"
        style={{ top: 24 + y, backgroundColor: color }}
      >
        {label}
      </div>
    );
  }

  return (
    <motion.div
      className="absolute flex h-11 w-[7.5rem] items-center justify-center rounded-md border-2 border-white/30 text-[10px] font-bold text-white shadow-md"
      style={{ top: 24 + y, backgroundColor: color }}
      initial={{ x: -100, opacity: 0, scale: 0.85 }}
      animate={{
        x: [-100, 72, 72, -100],
        opacity: [0, 1, 0.15, 0],
        scale: [0.85, 1, 0.7, 0.85],
      }}
      transition={{
        duration: CYCLE,
        delay,
        repeat: Infinity,
        ease: 'easeInOut',
        times: [0, 0.28, 0.42, 1],
      }}
    >
      {label}
    </motion.div>
  );
}

function Container({ paused }: { paused: boolean }) {
  return (
    <div className="relative z-20 mx-auto h-56 w-44">
      <div className="absolute inset-0 rounded-xl border-4 border-brand-blue bg-gradient-to-b from-slate-100 to-slate-200 shadow-xl">
        <div className="flex h-10 items-center justify-center rounded-t-lg bg-brand-blue text-[10px] font-bold tracking-wider text-white">
          BUILD
        </div>
        <div className="relative flex h-[calc(100%-2.5rem)] items-center justify-center overflow-hidden">
          {!paused && (
            <>
              <motion.div
                className="absolute h-16 w-16 rounded-full border-4 border-dashed border-brand-blue/40"
                animate={{ rotate: 360 }}
                transition={{ duration: 3, repeat: Infinity, ease: 'linear' }}
              />
              <motion.div
                className="h-2 w-20 rounded-full bg-brand-orange/80"
                animate={{ scaleX: [0.2, 1, 0.2], opacity: [0.4, 1, 0.4] }}
                transition={{ duration: 1.2, repeat: Infinity, ease: 'easeInOut' }}
              />
            </>
          )}
          {paused && (
            <div className="h-2 w-20 rounded-full bg-brand-orange/60" aria-hidden />
          )}
        </div>
      </div>
      <div className="absolute -bottom-2 left-1/2 h-3 w-36 -translate-x-1/2 rounded-full bg-black/10 blur-sm" />
    </div>
  );
}

function OutputProduct({ paused }: { paused: boolean }) {
  if (paused) {
    return (
      <div className="absolute right-2 top-1/2 z-30 flex -translate-y-1/2 flex-col items-center gap-1">
        <div className="flex h-20 w-24 flex-col items-center justify-center rounded-lg border-2 border-brand-orange bg-white shadow-lg">
          <span className="text-2xl" aria-hidden>
            ✓
          </span>
          <span className="text-[9px] font-bold text-brand-blue">Delivered</span>
        </div>
        <span className="text-[9px] font-medium text-muted">Finished product</span>
      </div>
    );
  }

  return (
    <motion.div
      className="absolute right-2 top-1/2 z-30 flex -translate-y-1/2 flex-col items-center gap-1"
      initial={{ x: 40, opacity: 0, scale: 0.8 }}
      animate={{
        x: [40, 0, 0, 40],
        opacity: [0, 1, 1, 0],
        scale: [0.8, 1, 1, 0.8],
      }}
      transition={{
        duration: CYCLE,
        repeat: Infinity,
        ease: 'easeInOut',
        times: [0, 0.5, 0.78, 1],
        delay: 0.2,
      }}
    >
      <div className="flex h-20 w-24 flex-col items-center justify-center rounded-lg border-2 border-brand-orange bg-white shadow-lg">
        <motion.span
          className="text-2xl text-brand-orange"
          animate={{ scale: [1, 1.15, 1] }}
          transition={{ duration: 0.6, repeat: Infinity, repeatDelay: 1.4 }}
          aria-hidden
        >
          ✓
        </motion.span>
        <span className="text-[9px] font-bold text-brand-blue">Delivered</span>
      </div>
      <span className="text-[9px] font-medium text-muted">Finished product</span>
    </motion.div>
  );
}

/** Looping hero visual: stack boxes enter a container; finished product exits. */
export function StackPipelineHero({ className = '' }: { className?: string }) {
  const reduceMotion = useReducedMotion();
  const paused = !!reduceMotion;

  return (
    <div
      className={`relative mx-auto aspect-square w-full max-w-md ${className}`}
      role="img"
      aria-label="Animation: technology stacks enter a build container and a finished website is delivered"
    >
      <div className="absolute inset-0 rounded-full bg-brand-blue/5 blur-3xl" />

      <div className="relative z-10 h-full min-h-[320px] w-full overflow-hidden rounded-2xl bg-gradient-to-br from-[#e8f4fc]/80 to-white/90 p-4 shadow-inner ring-1 ring-brand-blue/10">
        {/* Input lane */}
        <div className="absolute inset-y-0 left-0 w-[38%]">
          {STACKS.map((stack, i) => (
            <InputBox
              key={stack.label}
              label={stack.label}
              color={stack.color}
              row={i % 4}
              delay={i * 0.55}
              paused={paused}
            />
          ))}
          <span className="absolute bottom-3 left-3 text-[9px] font-semibold uppercase tracking-wide text-muted/80">
            Stacks in
          </span>
        </div>

        {/* Container */}
        <div className="absolute left-1/2 top-1/2 w-[44%] -translate-x-1/2 -translate-y-1/2">
          <Container paused={paused} />
        </div>

        {/* Output */}
        <OutputProduct paused={paused} />

        {/* Conveyor hints */}
        <div className="pointer-events-none absolute bottom-8 left-0 right-0 flex justify-between px-6 opacity-40">
          <div className="h-1 flex-1 max-w-[30%] rounded-full bg-brand-blue/30" />
          <div className="h-1 flex-1 max-w-[22%] rounded-full bg-brand-orange/40" />
        </div>
      </div>
    </div>
  );
}

