'use client';

import { useEffect, useRef } from 'react';
import { gsap, ensureGsapPlugins } from '@/lib/gsap-client';

const STACKS = [
  { name: 'React', color: '#61dafb' },
  { name: 'Next.js', color: '#1a1a2e' },
  { name: 'WordPress', color: '#21759b' },
  { name: 'Shopify', color: '#96bf48' },
  { name: 'Node.js', color: '#339933' },
  { name: 'GSAP', color: '#88ce02' },
] as const;

const POP_NUMBERS = ['150K', '1,000+', '3,000+', '99.9%', 'O(n)', 'λ', 'π', '01', '10', '∞'];

export function StackPipelineAnimation({ className = '' }: { className?: string }) {
  const rootRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;

    ensureGsapPlugins();
    const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    const gearOuter = root.querySelector('[data-gear-outer]');
    const gearInner = root.querySelector('[data-gear-inner]');
    const boxes = root.querySelectorAll('[data-stack-box]');
    const product = root.querySelector('[data-product]');
    const numbers = root.querySelectorAll('[data-pop-number]');
    const glow = root.querySelector('[data-glow]');

    if (reduced) {
      gsap.set([gearOuter, gearInner], { rotation: 18 });
      gsap.set(product, { opacity: 1, x: 0 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.to(gearOuter, { rotation: 360, duration: 14, repeat: -1, ease: 'none', transformOrigin: '200px 150px' });
      gsap.to(gearInner, { rotation: -360, duration: 9, repeat: -1, ease: 'none', transformOrigin: '200px 150px' });

      gsap.to(glow, {
        opacity: 0.85,
        scale: 1.08,
        duration: 2.2,
        repeat: -1,
        yoyo: true,
        ease: 'sine.inOut',
        transformOrigin: '200px 150px',
      });

      const master = gsap.timeline({ repeat: -1, repeatDelay: 0.6 });

      master
        .fromTo(
          boxes,
          { x: -120, opacity: 0, scale: 0.85 },
          {
            x: 0,
            opacity: 1,
            scale: 1,
            duration: 0.55,
            stagger: 0.22,
            ease: 'power2.out',
          },
          0
        )
        .to(
          boxes,
          {
            x: 68,
            opacity: 0,
            scale: 0.6,
            duration: 0.35,
            stagger: 0.08,
            ease: 'power2.in',
          },
          1.5
        )
        .fromTo(
          product,
          { x: -20, opacity: 0, scale: 0.7 },
          { x: 0, opacity: 1, scale: 1, duration: 0.7, ease: 'back.out(1.6)' },
          2.1
        )
        .to(product, { x: 130, opacity: 1, duration: 0.9, ease: 'power2.inOut' }, 2.9)
        .to(product, { opacity: 0, duration: 0.35 }, 3.7)
        .set(product, { x: -20, opacity: 0 }, 4.1)
        .set(boxes, { x: -120, opacity: 0, scale: 0.85 }, 4.1);

      numbers.forEach((el, i) => {
        gsap.fromTo(
          el,
          { opacity: 0, scale: 0.3, y: 0 },
          {
            opacity: 1,
            scale: 1,
            y: -28 - Math.random() * 20,
            duration: 0.7,
            ease: 'back.out(2)',
            repeat: -1,
            repeatDelay: 1.8 + i * 0.35,
            delay: i * 0.4,
            onRepeat: () => {
              gsap.set(el, { y: 0, opacity: 0, scale: 0.3 });
            },
          }
        );
      });
    }, root);

    return () => ctx.revert();
  }, []);

  return (
    <div
      ref={rootRef}
      className={`relative overflow-hidden rounded-2xl bg-gradient-to-br from-[#e8f4fc] via-white to-[#d4e8f7] shadow-xl ring-1 ring-brand-blue/10 ${className}`}
      role="img"
      aria-label="技術スタックがコンテナに投入され、完成したWebサイトが出力されるアニメーション"
    >
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_50%_40%,rgba(11,92,171,0.12),transparent_65%)]" />

      <svg
        viewBox="0 0 400 300"
        className="relative z-10 h-full w-full"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden
      >
        <defs>
          <linearGradient id="machineBody" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#0b5cab" />
            <stop offset="100%" stopColor="#084a8a" />
          </linearGradient>
          <linearGradient id="machineFace" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor="#1a7fd4" />
            <stop offset="100%" stopColor="#0b5cab" />
          </linearGradient>
          <linearGradient id="trackGrad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#c5dff0" />
            <stop offset="50%" stopColor="#e8f4fc" />
            <stop offset="100%" stopColor="#c5dff0" />
          </linearGradient>
          <filter id="softGlow" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="4" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          <filter id="productGlow" x="-40%" y="-40%" width="180%" height="180%">
            <feGaussianBlur stdDeviation="3" result="b" />
            <feMerge>
              <feMergeNode in="b" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Background grid — world of numbers */}
        {Array.from({ length: 8 }).map((_, row) =>
          Array.from({ length: 12 }).map((__, col) => (
            <text
              key={`${row}-${col}`}
              x={20 + col * 32}
              y={24 + row * 34}
              fill="rgba(11,92,171,0.06)"
              fontSize="11"
              fontFamily="monospace"
              fontWeight="700"
            >
              {((row + col) % 10).toString()}
            </text>
          ))
        )}

        {/* Input / output tracks */}
        <rect x="8" y="132" width="130" height="36" rx="6" fill="url(#trackGrad)" stroke="#b8d4ea" strokeWidth="1" />
        <rect x="262" y="132" width="130" height="36" rx="6" fill="url(#trackGrad)" stroke="#b8d4ea" strokeWidth="1" />
        <text x="24" y="154" fill="#5c6478" fontSize="9" fontWeight="700" letterSpacing="0.08em">
          IN
        </text>
        <text x="368" y="154" fill="#5c6478" fontSize="9" fontWeight="700" textAnchor="end" letterSpacing="0.08em">
          OUT
        </text>

        {/* Glow behind machine */}
        <ellipse data-glow cx="200" cy="150" rx="72" ry="58" fill="rgba(242,140,40,0.18)" opacity="0.5" />

        {/* Outer gear ring */}
        <g data-gear-outer filter="url(#softGlow)">
          <circle cx="200" cy="150" r="58" fill="none" stroke="#084a8a" strokeWidth="3" strokeDasharray="8 6" opacity="0.5" />
          {Array.from({ length: 16 }).map((_, i) => {
            const angle = (i / 16) * Math.PI * 2;
            const x = 200 + Math.cos(angle) * 62;
            const y = 150 + Math.sin(angle) * 62;
            return (
              <rect
                key={i}
                x={x - 5}
                y={y - 4}
                width="10"
                height="8"
                rx="1"
                fill="#0b5cab"
                transform={`rotate(${(angle * 180) / Math.PI + 90} ${x} ${y})`}
              />
            );
          })}
        </g>

        {/* Machine body */}
        <rect x="148" y="98" width="104" height="104" rx="14" fill="url(#machineBody)" stroke="#063d6e" strokeWidth="2" />
        <rect x="158" y="108" width="84" height="84" rx="10" fill="url(#machineFace)" opacity="0.95" />

        {/* Inner gear */}
        <g data-gear-inner>
          <circle cx="200" cy="150" r="28" fill="#063d6e" stroke="#f28c28" strokeWidth="2" />
          {Array.from({ length: 8 }).map((_, i) => {
            const angle = (i / 8) * Math.PI * 2;
            const x1 = 200 + Math.cos(angle) * 18;
            const y1 = 150 + Math.sin(angle) * 18;
            const x2 = 200 + Math.cos(angle) * 32;
            const y2 = 150 + Math.sin(angle) * 32;
            return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#7ec8ff" strokeWidth="3" strokeLinecap="round" />;
          })}
          <circle cx="200" cy="150" r="10" fill="#f28c28" />
          <text x="200" y="154" textAnchor="middle" fill="white" fontSize="8" fontWeight="800" fontFamily="monospace">
            dev
          </text>
        </g>

        {/* Popping numbers */}
        {POP_NUMBERS.map((num, i) => {
          const angle = (i / POP_NUMBERS.length) * Math.PI * 2 - Math.PI / 2;
          const x = 200 + Math.cos(angle) * 88;
          const y = 150 + Math.sin(angle) * 72;
          return (
            <text
              key={num}
              data-pop-number
              x={x}
              y={y}
              textAnchor="middle"
              fill={i % 2 === 0 ? '#f28c28' : '#0b5cab'}
              fontSize="11"
              fontWeight="800"
              fontFamily="monospace"
              opacity="0"
            >
              {num}
            </text>
          );
        })}

        {/* Stack boxes — enter from left */}
        <g transform="translate(0, 0)">
          {STACKS.map((stack, i) => (
            <g key={stack.name} data-stack-box opacity="0">
              <rect
                x={28}
                y={118 + i * 0.01}
                width="72"
                height="28"
                rx="4"
                fill="white"
                stroke="#d0e3f0"
                strokeWidth="1.5"
                transform={`translate(0, ${i * 2})`}
              />
              <rect x={28} y={118 + i * 0.01} width="5" height="28" rx="2" fill={stack.color} transform={`translate(0, ${i * 2})`} />
              <text
                x={42}
                y={136 + i * 2}
                fill="#1a1a2e"
                fontSize="10"
                fontWeight="700"
                fontFamily="system-ui, sans-serif"
              >
                {stack.name}
              </text>
            </g>
          ))}
        </g>

        {/* Single visible box on conveyor (animated position handled by group above - actually all boxes overlap, need separate y positions) */}
        {STACKS.map((stack, i) => (
          <g key={`box-${stack.name}`} data-stack-box opacity="0">
            <rect x={20} y={124} width="76" height="30" rx="5" fill="white" stroke="#b8d4ea" strokeWidth="1.5" />
            <rect x={20} y={124} width={6} height={30} rx="2" fill={stack.color} />
            <text x={34} y={143} fill="#1a1a2e" fontSize="10" fontWeight="700">
              {stack.name}
            </text>
          </g>
        ))}

        {/* Finished product — exits right */}
        <g data-product opacity="0" filter="url(#productGlow)">
          <rect x={268} y={122} width={88} height={56} rx="8" fill="white" stroke="#0b5cab" strokeWidth="2" />
          <rect x={276} y={130} width={72} height={10} rx="2" fill="#e8f4fc" />
          <rect x={276} y={146} width={48} height={6} rx="2" fill="#c5dff0" />
          <rect x={276} y={158} width={60} height={6} rx="2" fill="#c5dff0" />
          <circle cx="340" cy="148" r="6" fill="#f28c28" />
          <text x={282} y={168} fill="#0b5cab" fontSize="8" fontWeight="800">
            SITE
          </text>
          <path d="M352 138 L358 148 L352 158" fill="none" stroke="#f28c28" strokeWidth="2" strokeLinecap="round" />
        </g>

        {/* Decorative arrows */}
        <path d="M118 150 H138" stroke="#0b5cab" strokeWidth="2" markerEnd="url(#arrow)" opacity="0.6" />
        <path d="M252 150 H268" stroke="#f28c28" strokeWidth="2" opacity="0.8" />
      </svg>

      <p className="sr-only">React、Next.js、WordPressなどの技術ボックスが歯車状のコンテナに入り、数値が飛び出しながらWebサイトが完成して出力されます。</p>
    </div>
  );
}

'use client';

import { useEffect, useRef } from 'react';
import { gsap, ensureGsapPlugins } from '@/lib/gsap-client';

const STACKS = [
  { name: 'React', color: '#61dafb' },
  { name: 'Next.js', color: '#1a1a2e' },
  { name: 'WordPress', color: '#21759b' },
  { name: 'Shopify', color: '#96bf48' },
  { name: 'Node.js', color: '#339933' },
  { name: 'GSAP', color: '#88ce02' },
] as const;

const POP_NUMBERS = ['150K', '1,000+', '3,000+', '99.9%', 'O(n)', 'λ', 'π', '01', '10', '∞'];

const ORIGIN = { x: 200, y: 150 };

export function StackPipelineAnimation({ className = '' }: { className?: string }) {
  const rootRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;

    ensureGsapPlugins();
    const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    const gearOuter = root.querySelector('[data-gear-outer]');
    const gearInner = root.querySelector('[data-gear-inner]');
    const boxes = root.querySelectorAll('[data-stack-box]');
    const product = root.querySelector('[data-product]');
    const numbers = root.querySelectorAll('[data-pop-number]');
    const glow = root.querySelector('[data-glow]');

    if (!gearOuter || !gearInner || !product || !glow) return;

    if (reduced) {
      gsap.set([gearOuter, gearInner], { rotation: 24 });
      gsap.set(product, { opacity: 1 });
      gsap.set(boxes, { opacity: 0 });
      gsap.set(boxes[0], { opacity: 1, x: 55 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(boxes, { x: -95, opacity: 0, scale: 0.9 });
      gsap.set(product, { x: 55, opacity: 0, scale: 0.75 });

      gsap.to(gearOuter, {
        rotation: 360,
        duration: 16,
        repeat: -1,
        ease: 'none',
        transformOrigin: `${ORIGIN.x}px ${ORIGIN.y}px`,
      });
      gsap.to(gearInner, {
        rotation: -360,
        duration: 10,
        repeat: -1,
        ease: 'none',
        transformOrigin: `${ORIGIN.x}px ${ORIGIN.y}px`,
      });

      gsap.to(glow, {
        opacity: 0.9,
        scale: 1.1,
        duration: 2.4,
        repeat: -1,
        yoyo: true,
        ease: 'sine.inOut',
        transformOrigin: `${ORIGIN.x}px ${ORIGIN.y}px`,
      });

      const loop = gsap.timeline({ repeat: -1, repeatDelay: 0.4 });

      loop
        .to(boxes, {
          x: 55,
          opacity: 1,
          scale: 1,
          duration: 0.5,
          stagger: 0.28,
          ease: 'power2.out',
        })
        .to(
          boxes,
          {
            x: 55,
            opacity: 0,
            scale: 0.5,
            duration: 0.25,
            stagger: 0.12,
            ease: 'power2.in',
          },
          '+=0.15'
        )
        .fromTo(
          product,
          { x: 55, opacity: 0, scale: 0.75 },
          { x: 55, opacity: 1, scale: 1, duration: 0.55, ease: 'back.out(1.7)' },
          '-=0.1'
        )
        .to(product, { x: 168, duration: 0.85, ease: 'power2.inOut' })
        .to(product, { opacity: 0, duration: 0.3 })
        .set(boxes, { x: -95, opacity: 0, scale: 0.9 })
        .set(product, { x: 55, opacity: 0, scale: 0.75 });

      numbers.forEach((el, i) => {
        const angle = (i / POP_NUMBERS.length) * Math.PI * 2 - Math.PI / 2;
        const ox = Math.cos(angle) * 12;
        const oy = Math.sin(angle) * 10;

        gsap.fromTo(
          el,
          { opacity: 0, scale: 0.2, x: 0, y: 0 },
          {
            opacity: 1,
            scale: 1.15,
            x: ox,
            y: -32 + oy,
            duration: 0.65,
            ease: 'back.out(2.2)',
            repeat: -1,
            repeatDelay: 2.1,
            delay: 0.5 + i * 0.32,
            onRepeat: () => gsap.set(el, { opacity: 0, scale: 0.2, x: 0, y: 0 }),
          }
        );
      });
    }, root);

    return () => ctx.revert();
  }, []);

  return (
    <div
      ref={rootRef}
      className={`relative overflow-hidden rounded-2xl bg-gradient-to-br from-[#e8f4fc] via-white to-[#d4e8f7] shadow-xl ring-1 ring-brand-blue/15 ${className}`}
      role="img"
