      <div className="pointer-events-none absolute -right-8 -top-8 h-32 w-32 rounded-full bg-brand-orange/10 blur-2xl" />
      <div className="pointer-events-none absolute -bottom-6 -left-6 h-28 w-28 rounded-full bg-brand-blue/10 blur-2xl" />

      <svg viewBox="0 0 400 300" className="relative z-10 h-full w-full" xmlns="http://www.w3.org/2000/svg" aria-hidden>
