        </defs>

        {/* Number field backdrop */}
        {Array.from({ length: 6 }).map((_, row) =>
          Array.from({ length: 10 }).map((__, col) => (
            <text
              key={`n-${row}-${col}`}
              x={16 + col * 38}
              y={22 + row * 28}
              fill="rgba(11,92,171,0.07)"
              fontSize="12"
              fontFamily="'Nanum Gothic Coding', monospace"
              fontWeight="700"
            >
              {((row * 3 + col * 7) % 10).toString()}
            </text>
          ))
        )}

        {/* Conveyors */}
        <rect x="4" y="128" width="148" height="40" rx="8" fill="url(#sp-track)" stroke="#9ec5e0" strokeWidth="1.2" />
        <rect x="248" y="128" width="148" height="40" rx="8" fill="url(#sp-track)" stroke="#9ec5e0" strokeWidth="1.2" />
