        <g data-gear-outer filter="url(#sp-glow)">
          <circle cx={ORIGIN.x} cy={ORIGIN.y} r="60" fill="none" stroke="#084a8a" strokeWidth="2.5" strokeDasharray="7 5" opacity="0.45" />
          {Array.from({ length: 18 }).map((_, i) => {
            const angle = (i / 18) * Math.PI * 2;
            const x = ORIGIN.x + Math.cos(angle) * 64;
            const y = ORIGIN.y + Math.sin(angle) * 64;
            return (
              <rect
                key={`tooth-${i}`}
                x={x - 5}
                y={y - 4}
                width="10"
                height="8"
                rx="1.5"
                fill="#084a8a"
                transform={`rotate(${(angle * 180) / Math.PI + 90} ${x} ${y})`}
              />
            );
