          {Array.from({ length: 8 }).map((_, i) => {
            const angle = (i / 8) * Math.PI * 2;
            return (
              <line
                key={`spoke-${i}`}
                x1={ORIGIN.x + Math.cos(angle) * 16}
                y1={ORIGIN.y + Math.sin(angle) * 16}
                x2={ORIGIN.x + Math.cos(angle) * 34}
                y2={ORIGIN.y + Math.sin(angle) * 34}
                stroke="#9ed4ff"
                strokeWidth="3.5"
                strokeLinecap="round"
              />
            );
          })}
          <circle cx={ORIGIN.x} cy={ORIGIN.y} r="11" fill="#f28c28" />
          <text x={ORIGIN.x} y={ORIGIN.y + 3.5} textAnchor="middle" fill="white" fontSize="7.5" fontWeight="800" fontFamily="monospace">
            dev
          </text>
        </g>

        {/* Popping metrics */}
        {POP_NUMBERS.map((num, i) => {
          const angle = (i / POP_NUMBERS.length) * Math.PI * 2 - Math.PI / 2;
          const x = ORIGIN.x + Math.cos(angle) * 92;
          const y = ORIGIN.y + Math.sin(angle) * 76;
          return (
            <text
              key={num}
              data-pop-number
              x={x}
              y={y}
              textAnchor="middle"
              fill={i % 2 === 0 ? '#f28c28' : '#0b5cab'}
              fontSize="11"
              fontWeight="800"
              fontFamily="monospace"
              opacity="0"
            >
              {num}
            </text>
          );
        })}

        {/* Stack boxes on shared conveyor (same anchor; GSAP staggers visibility) */}
        <g transform="translate(52, 133)">
          {STACKS.map((stack) => (
            <g key={stack.name} data-stack-box>
              <rect x="0" y="0" width="80" height="32" rx="6" fill="white" stroke="#b8d4ea" strokeWidth="1.5" />
              <rect x="0" y="0" width="7" height="32" rx="3" fill={stack.color} />
              <text x="14" y="20" fill="#1a1a2e" fontSize="11" fontWeight="700" fontFamily="system-ui, sans-serif">
                {stack.name}
              </text>
            </g>
          ))}
        </g>

        {/* Output product */}
        <g data-product transform="translate(248, 126)" opacity="0">
          <rect x="0" y="0" width="92" height="58" rx="9" fill="white" stroke="#0b5cab" strokeWidth="2.5" />
          <rect x="8" y="10" width="76" height="11" rx="3" fill="#e8f4fc" />
          <rect x="8" y="28" width="52" height="7" rx="2" fill="#c5dff0" />
          <rect x="8" y="40" width="64" height="7" rx="2" fill="#c5dff0" />
          <circle cx="78" cy="22" r="7" fill="#f28c28" />
          <text x="10" y="54" fill="#0b5cab" fontSize="9" fontWeight="800" letterSpacing="0.06em">
            LIVE SITE
          </text>
          <path
            d="M98 18 L106 29 L98 40"
            fill="none"
            stroke="#f28c28"
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </g>

        {/* Flow arrows */}
        <path d="M138 148 H152" stroke="#0b5cab" strokeWidth="2.5" strokeLinecap="round" opacity="0.55" />
        <path d="M248 148 H262" stroke="#f28c28" strokeWidth="2.5" strokeLinecap="round" opacity="0.85" />
      </svg>

      <p className="sr-only">
        React、Next.js、WordPressなどの技術ボックスが歯車状のコンテナに入り、数値が飛び出しながらWebサイトが完成して出力されます。
      </p>
    </div>
  );
}

